CREATE TABLE "AgreementSignatureRequest" ("id" TEXT NOT NULL,"companyId" TEXT NOT NULL,"agreementId" TEXT NOT NULL,"agreementVersionId" TEXT NOT NULL,"agreementArtifactId" TEXT NOT NULL,"artifactChecksum" TEXT NOT NULL,"signerDisplayName" TEXT NOT NULL,"signerEmail" TEXT NOT NULL,"signerRole" TEXT NOT NULL,"signingMode" TEXT NOT NULL,"signingOrder" INTEGER NOT NULL,"status" TEXT NOT NULL,"signatureMethod" TEXT NOT NULL,"requestIdentity" TEXT NOT NULL,"tokenDigest" TEXT NOT NULL,"requestedAt" TIMESTAMP(3) NOT NULL,"requestedByUserId" TEXT NOT NULL,"expiresAt" TIMESTAMP(3) NOT NULL,"revokedAt" TIMESTAMP(3),"failedAt" TIMESTAMP(3),"failureCode" TEXT,"providerReference" TEXT,"correlationId" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "AgreementSignatureRequest_pkey" PRIMARY KEY("id"),CONSTRAINT "AgreementSignatureRequest_status_check" CHECK("status" IN('REQUESTED','AVAILABLE','SIGNED','DECLINED','REVOKED','EXPIRED','FAILED')),CONSTRAINT "AgreementSignatureRequest_role_check" CHECK("signerRole" IN('CLIENT','COTARION_REPRESENTATIVE')),CONSTRAINT "AgreementSignatureRequest_mode_check" CHECK("signingMode" IN('PARALLEL','ORDERED')));
CREATE UNIQUE INDEX "AgreementSignatureRequest_tokenDigest_key" ON "AgreementSignatureRequest"("tokenDigest"); CREATE UNIQUE INDEX "AgreementSignatureRequest_companyId_requestIdentity_key" ON "AgreementSignatureRequest"("companyId","requestIdentity"); CREATE UNIQUE INDEX "AgreementSignatureRequest_agreementVersionId_signerEmail_signerRole_key" ON "AgreementSignatureRequest"("agreementVersionId","signerEmail","signerRole"); CREATE UNIQUE INDEX "AgreementSignatureRequest_id_companyId_key" ON "AgreementSignatureRequest"("id","companyId"); CREATE INDEX "AgreementSignatureRequest_companyId_agreementId_requestedAt_idx" ON "AgreementSignatureRequest"("companyId","agreementId","requestedAt"); CREATE INDEX "AgreementSignatureRequest_companyId_status_expiresAt_idx" ON "AgreementSignatureRequest"("companyId","status","expiresAt");
ALTER TABLE "AgreementSignatureRequest" ADD CONSTRAINT "AgreementSignatureRequest_agreementVersionId_companyId_fkey" FOREIGN KEY("agreementVersionId","companyId") REFERENCES "AgreementVersion"("id","companyId") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "AgreementSignatureRequest" ADD CONSTRAINT "AgreementSignatureRequest_agreementArtifactId_fkey" FOREIGN KEY("agreementArtifactId") REFERENCES "AgreementArtifact"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
CREATE TABLE "AgreementSignatureEvidence"("id" TEXT NOT NULL,"signatureRequestId" TEXT NOT NULL,"companyId" TEXT NOT NULL,"outcome" TEXT NOT NULL,"occurredAt" TIMESTAMP(3) NOT NULL,"signatureMethod" TEXT NOT NULL,"typedSignerName" TEXT,"explicitConfirmation" BOOLEAN NOT NULL,"signerMessage" TEXT,"requestIdentity" TEXT NOT NULL,"correlationId" TEXT NOT NULL,"providerReference" TEXT,"artifactChecksum" TEXT NOT NULL,"signerSnapshot" JSONB NOT NULL,CONSTRAINT "AgreementSignatureEvidence_pkey" PRIMARY KEY("id")); CREATE UNIQUE INDEX "AgreementSignatureEvidence_signatureRequestId_key" ON "AgreementSignatureEvidence"("signatureRequestId"); CREATE UNIQUE INDEX "AgreementSignatureEvidence_companyId_requestIdentity_key" ON "AgreementSignatureEvidence"("companyId","requestIdentity"); CREATE INDEX "AgreementSignatureEvidence_companyId_occurredAt_idx" ON "AgreementSignatureEvidence"("companyId","occurredAt"); ALTER TABLE "AgreementSignatureEvidence" ADD CONSTRAINT "AgreementSignatureEvidence_signatureRequestId_companyId_fkey" FOREIGN KEY("signatureRequestId","companyId") REFERENCES "AgreementSignatureRequest"("id","companyId") ON DELETE RESTRICT ON UPDATE CASCADE;
CREATE TABLE "AgreementSignatureEvent"("id" TEXT NOT NULL,"signatureRequestId" TEXT NOT NULL,"companyId" TEXT NOT NULL,"eventType" TEXT NOT NULL,"occurredAt" TIMESTAMP(3) NOT NULL,"actorUserId" TEXT,"correlationId" TEXT NOT NULL,"evidence" JSONB NOT NULL,CONSTRAINT "AgreementSignatureEvent_pkey" PRIMARY KEY("id")); CREATE INDEX "AgreementSignatureEvent_companyId_signatureRequestId_occurredAt_idx" ON "AgreementSignatureEvent"("companyId","signatureRequestId","occurredAt"); ALTER TABLE "AgreementSignatureEvent" ADD CONSTRAINT "AgreementSignatureEvent_signatureRequestId_companyId_fkey" FOREIGN KEY("signatureRequestId","companyId") REFERENCES "AgreementSignatureRequest"("id","companyId") ON DELETE RESTRICT ON UPDATE CASCADE;
CREATE TABLE "AgreementSignatureAccess"("id" TEXT NOT NULL,"signatureRequestId" TEXT NOT NULL,"companyId" TEXT NOT NULL,"accessedAt" TIMESTAMP(3) NOT NULL,"accessType" TEXT NOT NULL,"correlationId" TEXT NOT NULL,CONSTRAINT "AgreementSignatureAccess_pkey" PRIMARY KEY("id")); CREATE INDEX "AgreementSignatureAccess_companyId_signatureRequestId_accessedAt_idx" ON "AgreementSignatureAccess"("companyId","signatureRequestId","accessedAt"); ALTER TABLE "AgreementSignatureAccess" ADD CONSTRAINT "AgreementSignatureAccess_signatureRequestId_companyId_fkey" FOREIGN KEY("signatureRequestId","companyId") REFERENCES "AgreementSignatureRequest"("id","companyId") ON DELETE RESTRICT ON UPDATE CASCADE;
CREATE TRIGGER "AgreementSignatureEvidence_immutable" BEFORE UPDATE OR DELETE ON "AgreementSignatureEvidence" FOR EACH ROW EXECUTE FUNCTION protect_immutable_row(); CREATE TRIGGER "AgreementSignatureEvent_immutable" BEFORE UPDATE OR DELETE ON "AgreementSignatureEvent" FOR EACH ROW EXECUTE FUNCTION protect_immutable_row(); CREATE TRIGGER "AgreementSignatureAccess_immutable" BEFORE UPDATE OR DELETE ON "AgreementSignatureAccess" FOR EACH ROW EXECUTE FUNCTION protect_immutable_row();
CREATE UNIQUE INDEX "AgreementSignatureEvidence_signatureRequestId_companyId_key" ON "AgreementSignatureEvidence"("signatureRequestId","companyId");
